16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	// Rounds up in MHPCO's favor, guarding against floating-point drift
25	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
26	const roundUpInFavor = (amount: number): number =>
27	  Math.ceil(Number(amount.toFixed(6)));
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE_PREMIUM = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	// A same-type group of exactly BLOCK_SIZE components forms one block priced at
37	// BLOCK_BASE_PREMIUM; any other count is priced per component. (Multi-block and
38	// block-plus-leftover pricing are not yet implemented.)
39	const componentGroupBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : count * COMPONENT_BASE_PREMIUM;
43	
44	const itemBasePremium = (item: Item): number =>
45	  isComponent(item) ? COMPONENT_BASE_PREMIUM : BASE_PREMIUMS[item.type];
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const FIRST_INSURANCE_RATE = 0.1;
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const LOYALTY_YEARS_THRESHOLD = 2;
51	
52	const itemSurcharge = (item: Item): number =>
53	  item.cursed ? CURSE_SURCHARGE_RATE * itemBasePremium(item) : 0;
54	
55	const countByType = (items: Item[]): Record<string, number> =>
56	  items.reduce<Record<string, number>>((counts, item) => {
57	    counts[item.type] = (counts[item.type] ?? 0) + 1;
58	    return counts;
59	  }, {});
60	
61	const sum = (values: number[]): number =>
62	  values.reduce((running, value) => running + value, 0);
63	
64	const basePremiumTotal = (items: Item[]): number => {
65	  const mainItems = items.filter((item) => !isComponent(item));
66	  const components = items.filter(isComponent);
67	
68	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
69	  const componentsTotal = sum(
70	    Object.values(countByType(components)).map(componentGroupBasePremium),
71	  );
72	
73	  return mainItemsTotal + componentsTotal;
74	};
75	
76	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
77	  const policyBase = basePremiumTotal(items);
78	  const surcharges = sum(items.map(itemSurcharge));
79	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
80	  const loyalty =
81	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
82	      ? policyBase * LOYALTY_DISCOUNT_RATE
83	      : 0;
84	  const exactPremium =
85	    policyBase + surcharges + firstInsurance - loyalty + PROCESSING_FEE;
86	  return { premium: roundUpInFavor(exactPremium) };
87	};
