// Net policy-level adjustment derived from the policy base: the first-insurance
// surcharge (always) minus the loyalty discount (for established customers).
const policyBaseModifiers = (customer: Customer, policyBase: number): number => {
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
      ? policyBase * LOYALTY_DISCOUNT_RATE
      : 0;
  return firstInsurance - loyaltyDiscount;
};

export const quote = (customer: Customer, items: Item[]): QuoteResult => {
  const policyBase = basePremiumTotal(items);
  const surcharges = sum(items.map(itemSurcharge));
  const exactPremium =
    policyBase +
    surcharges +
    policyBaseModifiers(customer, policyBase) +
    PROCESSING_FEE;
  return { premium: roundUpInFavor(exactPremium) };
};
